insert into compass.ollama_document_chunks (
  document_id,
  chunk_id,
  content,
  embedding,
  metadata,
  created_at,
  updated_at
)
select
  m.source_document_id as document_id,
  m.target_chunk_id as chunk_id,
  c.content,
  c.embedding,
  jsonb_build_object(
    'rag_gate', 'RAG-3F',
    'source_vendor', m.source_vendor,
    'canonical_title', m.canonical_title,
    'source_title', m.source_title,
    'source_url', m.source_url,
    'source_document_id', m.source_document_id,
    'source_chunk_id', m.source_chunk_id,
    'source_row_id', m.source_row_id,
    'topic_labels', string_to_array(nullif(m.topic_labels, ''), '|'),
    'fixture_matches', string_to_array(nullif(m.fixture_matches, ''), '|'),
    'quality_score', m.quality_score,
    'imported_from', 'document_chunks',
    'embedding_source', 'document_chunks.embedding',
    'embedding_dimension', vector_dims(c.embedding),
    'full_content_hash', md5(regexp_replace(coalesce(c.content, ''), '\s+', ' ', 'g')),
    'sample_bucket', m.sample_bucket,
    'created_by_gate', 'RAG-3F'
  ) as metadata,
  now() as created_at,
  now() as updated_at
from manifest m
join compass.document_chunks c
  on c.id = m.source_row_id
where c.document_id = m.source_document_id
  and c.chunk_id = m.source_chunk_id
  and c.content is not null
  and c.embedding is not null
  and vector_dims(c.embedding) = 1024
  and not exists (
    select 1
    from compass.ollama_document_chunks o
    where o.chunk_id = m.target_chunk_id
       or (o.metadata->>'rag_gate' = 'RAG-3F' and o.metadata->>'source_row_id' = m.source_row_id)
  )
on conflict do nothing;
